import numpy as np
from sentence_transformers import SentenceTransformer

class LightweightRAG:
    def __init__(self, use_f16=True):
        self.model = SentenceTransformer("BAAI/bge-small-en-v1.5")
        self.use_f16 = use_f16
        self.chunks = []
        self.index = None

    def ingest(self, texts, chunk_size=40, overlap=10):
        for text in texts:
            words = text.split()
            for i in range(0, len(words), chunk_size - overlap):
                c = " ".join(words[i:i + chunk_size])
                if c:
                    self.chunks.append(c)
        vecs = self.model.encode(self.chunks, normalize_embeddings=True)
        self.index = vecs.astype(np.float16) if self.use_f16 else vecs

    def retrieve(self, query, top_k=3):
        q = self.model.encode("Represent this sentence: " + query, normalize_embeddings=True)
        if self.use_f16:
            q = q.astype(np.float16)
        scores = (q @ self.index.T).astype(np.float32)
        top_idx = np.argsort(scores)[::-1][:top_k]
        return [{"chunk": self.chunks[i], "score": float(scores[i])} for i in top_idx]

    def memory_usage_mb(self):
        return self.index.nbytes / (1024 ** 2) if self.index is not None else 0.0
